LFightIdleConst.FormatBoardPathKey = function(boardRefId,pathIndex)
	return boardRefId.."_"..pathIndex
end

LFightIdleConst.CloneArrayTable = function(fromTable)
	local retTbl = {}
	for k,v in ipairs(fromTable) do
		table.insert(retTbl,v)
	end
	return retTbl
end

function LFightIdleConst.GenerateSeqList(len)
	local tbl = {}
	for k=1,len do
		table.insert(tbl,k)
	end
	return tbl
end

---放大倍数随机两个整数之间
function LFightIdleConst.RandIntegerBetween(min,max)
	return LFightIdleConst.RandInteger(max - min + 1) + min - 1
end

---放大倍数随机
function LFightIdleConst.RandInteger(len)
	if len == 1 then return 1 end
	local rand = math.random(1,len * 100)
	rand = rand % len + 1
	return rand
end


function LFightIdleConst.RandPos(posData,index)
	local left = posData.left
	local right = posData.right

	local minPos = Vector3(left.x,left.y,left.z)
	local maxPos = Vector3(right.x,right.y,right.z)

	local x = 0
	if(index) then
		if index % 2 == 0 then
			x = Mathf.Lerp((left.x + right.x) * 0.5,right.x,math.random())
		else
			x = Mathf.Lerp(left.x,(left.x + right.x) * 0.5,math.random())
		end
	else
		x = Mathf.Lerp(left.x,right.x,math.random())
	end

	local y = left.y
	local z = left.z

	local nowPos = Vector3(x,y,z)

	return minPos,maxPos,nowPos
end

function LFightIdleConst.Approximately(a,b)
	local abs = Mathf.Abs(a-b)
	--unity 世界坐标有个最小改变值大概是0.000005 所以这里就取 五位
	return abs <= 0.00001
end


function LFightIdleConst.CalcMoveAndJump(nowPos,nowMinPos,nowMaxPos,nextMinPos,nextMaxPos)
	local jumpDistance = 0.3
	local downDis = 0.1 --不刚好跳到边边
	local nowX = nowPos.x
	local tarX = nil --落地位置
	local jumpX = nil --起跳位置
	if nowMaxPos.x <= nextMinPos.x then -- 在左边,没有重合部分, 当前往右走，跳到下一个板子左边
		tarX = nextMinPos.x + downDis
		jumpX = tarX - jumpDistance

		if jumpX > nowMaxPos.x then
			jumpX = nowMaxPos.x
		end
		--确保jumX在nowX 和tarX 之间
		if jumpX < nowX then
			jumpX = nowX
		end

	elseif nowMinPos.x >= nextMaxPos.x then -- 在右边，没有重合部分,当前往左走，跳到下一个板子右边
		tarX = nextMaxPos.x - downDis
		jumpX = tarX + jumpDistance
		if jumpX < nowMinPos.x then
			jumpX = nowMinPos.x
		end
		--确保jumX在nowX 和tarX 之间
		if jumpX > nowX then
			jumpX = nowX
		end
	else
		-- 有相交部分
		if nowX <= nextMinPos.x then -- 在左边,当前往右走,跳到下一个板子
			tarX = nextMinPos.x + downDis --落地位置
			jumpX = tarX - jumpDistance --起跳位置
			--确保jumX在nowX 和tarX 之间
			if jumpX < nowX then
				jumpX = nowX
			end

		elseif nowX >= nextMaxPos.x then --在右边,当前往左走,跳到下一个板子
			tarX = nextMaxPos.x - downDis --落地位置
			jumpX = tarX + jumpDistance --起跳位置
			--确保jumX在nowX 和tarX 之间
			if jumpX > nowX then
				jumpX = nowX
			end
		else
			--在之间 可以直接起跳
			tarX = nowX
			jumpX = nowX
		end
	end

	local movePos
	--当起跳位置和当前位置接近时，不需要移动
	if not LFightIdleConst.Approximately(nowX,jumpX) then
		movePos = Vector3(jumpX,nowPos.y,0)
	end
	local jumpDownPos = Vector3(tarX,nextMinPos.y,0)
	return movePos,jumpDownPos
end

