function LFightIdleConst.CreateSkillData(skillRefId, bNormal, skin)
	local skillRef = gModelSkill:GetSkillRef(skillRefId)

	if not skillRef then return nil end
	if skillRef.type ~= 1 and not bNormal then return nil end

	local LSkillData = LxRequire("LApp.Models.Data.LSkillData")

	local effectList = gModelSkill:GetEffectList(skillRefId) or {}
	for k,effectRefId in ipairs(effectList) do
		local skillEffectRef = gModelSkill:GetSkillEffectRef(effectRefId)
		local effectType = skillEffectRef and skillEffectRef.effectType or -1
		if effectType == 1 or effectType == 2  or bNormal then

			local expressId = skillEffectRef.skillShowEff
			--多种攻击次数的，选第一种攻击次数的表现
			expressId = gModelSkill:GetSkillExpressionId(expressId, 0)
			if skin and skin > 0 then
				expressId = gModelSkill:GetSkinExpress(skin,expressId,true)
			end
			if not expressId then return nil end

			local skillData = LSkillData:New()
			skillData:InitData(skillRefId,effectRefId,expressId,bNormal)
			skillData:InitSkillCalcData()
			return skillData
		end
	end
	return nil
end

return LFightIdleConst